import{_ as r,o as t,c as a,ae as i}from"./chunks/framework.CyZiF_rV.js";const c=JSON.parse('{"title":"XAdES Signature","description":"","frontmatter":{},"headers":[],"relativePath":"en/auth/podpis-xades.md","filePath":"en/auth/podpis-xades.md"}'),o={name:"en/auth/podpis-xades.md"};function s(n,e,d,l,h,w){return t(),a("div",null,[...e[0]||(e[0]=[i('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/auth/podpis-xades.md" target="_blank" rel="noreferrer">auth/podpis-xades.md</a></p></blockquote><h1 id="xades-signature" tabindex="-1">XAdES Signature <a class="header-anchor" href="#xades-signature" aria-label="Permalink to &quot;XAdES Signature&quot;">​</a></h1><p><a href="https://www.w3.org/TR/XAdES/" target="_blank" rel="noreferrer">https://www.w3.org/TR/XAdES/</a></p><h2 id="technical-parameters-of-xades-signature" tabindex="-1">Technical Parameters of XAdES Signature <a class="header-anchor" href="#technical-parameters-of-xades-signature" aria-label="Permalink to &quot;Technical Parameters of XAdES Signature&quot;">​</a></h2><h3 id="accepted-signature-formats" tabindex="-1">Accepted Signature Formats <a class="header-anchor" href="#accepted-signature-formats" aria-label="Permalink to &quot;Accepted Signature Formats&quot;">​</a></h3><ul><li><strong>enveloped</strong></li><li><strong>enveloping</strong></li></ul><p>Signature in <strong>detached</strong> format is not accepted.</p><h3 id="accepted-transforms-contained-in-xades-signature" tabindex="-1">Accepted Transforms Contained in XAdES Signature <a class="header-anchor" href="#accepted-transforms-contained-in-xades-signature" aria-label="Permalink to &quot;Accepted Transforms Contained in XAdES Signature&quot;">​</a></h3><ul><li><a href="http://www.w3.org/TR/1999/REC-xpath-19991116" target="_blank" rel="noreferrer">http://www.w3.org/TR/1999/REC-xpath-19991116</a> - not(ancestor-or-self::ds:Signature)</li><li><a href="http://www.w3.org/2002/06/xmldsig-filter2" target="_blank" rel="noreferrer">http://www.w3.org/2002/06/xmldsig-filter2</a></li><li><a href="http://www.w3.org/2000/09/xmldsig#enveloped-signature" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#enveloped-signature</a></li><li><a href="http://www.w3.org/2000/09/xmldsig#base64" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#base64</a></li><li><a href="http://www.w3.org/2006/12/xml-c14n11" target="_blank" rel="noreferrer">http://www.w3.org/2006/12/xml-c14n11</a></li><li><a href="http://www.w3.org/2006/12/xml-c14n11#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/2006/12/xml-c14n11#WithComments</a></li><li><a href="http://www.w3.org/2001/10/xml-exc-c14n#" target="_blank" rel="noreferrer">http://www.w3.org/2001/10/xml-exc-c14n#</a></li><li><a href="http://www.w3.org/2001/10/xml-exc-c14n#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/2001/10/xml-exc-c14n#WithComments</a></li><li><a href="http://www.w3.org/TR/2001/REC-xml-c14n-20010315" target="_blank" rel="noreferrer">http://www.w3.org/TR/2001/REC-xml-c14n-20010315</a></li><li><a href="http://www.w3.org/TR/2001/REC-xml-c14n-20010315#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/TR/2001/REC-xml-c14n-20010315#WithComments</a></li></ul><h3 id="accepted-xades-profiles" tabindex="-1">Accepted XAdES Profiles <a class="header-anchor" href="#accepted-xades-profiles" aria-label="Permalink to &quot;Accepted XAdES Profiles&quot;">​</a></h3><ul><li>XAdES-BES</li><li>XAdES-EPES</li><li>XAdES-T</li><li>XAdES-LT</li><li>XAdES-C</li><li>XAdES-X</li><li>XAdES-XL</li><li>XAdES-A</li><li>XAdES-ERS</li><li>XAdES-BASELINE-B</li><li>XAdES-BASELINE-T</li><li>XAdES-BASELINE-LT</li><li>XAdES-BASELINE-LTA</li></ul><h3 id="signedinfo-signature-algorithm-ds-signaturemethod" tabindex="-1">SignedInfo Signature Algorithm (<code>ds:SignatureMethod</code>) <a class="header-anchor" href="#signedinfo-signature-algorithm-ds-signaturemethod" aria-label="Permalink to &quot;SignedInfo Signature Algorithm (`ds:SignatureMethod`)&quot;">​</a></h3><p><strong>RSASSA-PKCS1-v1_5</strong><br><a href="http://www.w3.org/2000/09/xmldsig#rsa-sha1" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#rsa-sha1</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha384</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha512</a></p><p>Minimum key length: 2048 bits</p><p><strong>RSASSA-PSS</strong><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha1-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha1-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha256-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha256-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha384-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha384-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha512-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha512-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-256-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-256-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-384-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-384-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-512-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-512-rsa-MGF1</a></p><p>Minimum key length: 2048 bits</p><p><strong>ECDSA</strong><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha1" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha1</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha384</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha512</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-256" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-256</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-384" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-384</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-512" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-512</a></p><p>Minimum curve size: 256 bits</p><blockquote><p>For ECDSA, the <code>SignatureValue</code> is encoded as <code>R || S</code> (fixed-field concatenation) according to XML Signature (XMLDSIG) 1.1 / <a href="https://datatracker.ietf.org/doc/html/rfc4050#section-3.3" target="_blank" rel="noreferrer">RFC 4050</a>.</p></blockquote><h3 id="hash-algorithms-in-references-digestmethod" tabindex="-1">Hash Algorithms in References (<code>DigestMethod</code>) <a class="header-anchor" href="#hash-algorithms-in-references-digestmethod" aria-label="Permalink to &quot;Hash Algorithms in References (`DigestMethod`)&quot;">​</a></h3><p><code>DigestMethod</code> refers to the hash of data indicated by references in <code>SignedInfo</code> (i.e., <code>SignedInfo / Reference / DigestMethod</code>) and is independent of <code>SignatureMethod</code> (the <code>SignedInfo</code> signature algorithm).</p><p>The same hash algorithms are also used for calculating hashes of qualifying properties, in particular certificate hash in <code>SigningCertificate / CertDigest / DigestMethod</code>.</p><p><a href="http://www.w3.org/2000/09/xmldsig#sha1" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#sha1</a><br><a href="http://www.w3.org/2001/04/xmlenc#sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmlenc#sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#sha384</a><br><a href="http://www.w3.org/2001/04/xmlenc#sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmlenc#sha512</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-256" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-256</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-384" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-384</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-512" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-512</a></p><h3 id="allowed-certificate-types" tabindex="-1">Allowed Certificate Types <a class="header-anchor" href="#allowed-certificate-types" aria-label="Permalink to &quot;Allowed Certificate Types&quot;">​</a></h3><p>Allowed certificate types in XAdES signature:</p><ul><li>Qualified certificate for natural persons – containing PESEL number or NIP of a person authorized to act on behalf of a company,</li><li>Qualified certificate for organizations (so-called company seal) – containing NIP number,</li><li>Trusted Profile (ePUAP) – enables document signing; used by natural persons,</li><li>Internal KSeF certificate – issued by the KSeF system. This certificate is not a qualified certificate, but is honored in the authentication process.</li></ul><p><strong>Qualified certificate</strong> – a certificate issued by a qualified trust service provider, listed in the <a href="https://eidas.ec.europa.eu/efda/trust-services/browse/eidas/tls" target="_blank" rel="noreferrer">EU Trusted List (EUTL)</a>, in accordance with the eIDAS regulation. KSeF accepts qualified certificates issued in Poland and in other European Union member states.</p><h3 id="required-attributes-of-qualified-certificates" tabindex="-1">Required Attributes of Qualified Certificates <a class="header-anchor" href="#required-attributes-of-qualified-certificates" aria-label="Permalink to &quot;Required Attributes of Qualified Certificates&quot;">​</a></h3><h4 id="qualified-signature-certificates-issued-for-natural-persons" tabindex="-1">Qualified signature certificates (issued for natural persons) <a class="header-anchor" href="#qualified-signature-certificates-issued-for-natural-persons" aria-label="Permalink to &quot;Qualified signature certificates (issued for natural persons)&quot;">​</a></h4><p>Required subject attributes:<br></p><table tabindex="0"><thead><tr><th>Identifier (OID)</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>2.5.4.42</td><td>givenName</td><td>given name</td></tr><tr><td>2.5.4.4</td><td>surname</td><td>surname</td></tr><tr><td>2.5.4.5</td><td>serialNumber</td><td>serial number</td></tr><tr><td>2.5.4.3</td><td>commonName</td><td>common name of certificate owner</td></tr><tr><td>2.5.4.6</td><td>countryName</td><td>country name, ISO 3166 code</td></tr></tbody></table><p>Recognized patterns for <code>serialNumber</code> attribute:<br><strong>(PNOPL|PESEL).*?(?&lt;number&gt;\\d{11})</strong><br><strong>(TINPL|NIP).*?(?&lt;number&gt;\\d{10})</strong><br></p><h4 id="qualified-seal-certificates-issued-for-organizations" tabindex="-1">Qualified seal certificates (issued for organizations) <a class="header-anchor" href="#qualified-seal-certificates-issued-for-organizations" aria-label="Permalink to &quot;Qualified seal certificates (issued for organizations)&quot;">​</a></h4><p>Required subject attributes:<br></p><table tabindex="0"><thead><tr><th>Identifier (OID)</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>2.5.4.10</td><td>organizationName</td><td>full formal name of the entity for which the certificate is issued</td></tr><tr><td>2.5.4.97</td><td>organizationIdentifier</td><td>entity identifier</td></tr><tr><td>2.5.4.3</td><td>commonName</td><td>common name of organization</td></tr><tr><td>2.5.4.6</td><td>countryName</td><td>country name, ISO 3166 code</td></tr></tbody></table><p>Prohibited subject attributes:</p><table tabindex="0"><thead><tr><th>Identifier (OID)</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>2.5.4.42</td><td>givenName</td><td>given name</td></tr><tr><td>2.5.4.4</td><td>surname</td><td>surname</td></tr></tbody></table><p>Recognized patterns for <code>organizationIdentifier</code> attribute:<br><strong>(VATPL).*?(?&lt;number&gt;\\d{10})</strong><br></p><h3 id="certificate-fingerprint" tabindex="-1">Certificate Fingerprint <a class="header-anchor" href="#certificate-fingerprint" aria-label="Permalink to &quot;Certificate Fingerprint&quot;">​</a></h3><p>For qualified certificates that do not have proper identifiers stored in the subject attribute OID.2.5.4.5, it is possible to authenticate with such a certificate after prior granting permissions to the SHA-256 hash (so-called fingerprint) of that certificate.</p><p>Related documents:</p><ul><li><a href="./../uwierzytelnianie.html">Authentication</a></li></ul>',42)])])}const f=r(o,[["render",s]]);export{c as __pageData,f as default};
